const updateOverdueSalesAndAccountsGlobal = `-- name: UpdateOverdueSalesAndAccountsGlobal :many
WITH updated_accounts AS (
    UPDATE accounts_receivable
    SET status = 'overdue'
    WHERE status = 'pending'
        AND due_date::DATE < CURRENT_DATE
    RETURNING sale_id
)
UPDATE sales
SET status = 'overdue',
    updated_at = CURRENT_TIMESTAMP
WHERE id IN (
        SELECT sale_id
        FROM updated_accounts
    )
    AND status NOT IN ('paid', 'canceled')
RETURNING id AS sale_id,
    customer_id, company_id
`

type UpdateOverdueSalesAndAccountsGlobalRow struct {
	SaleID     pgtype.UUID `json:"sale_id"`
	CustomerID pgtype.UUID `json:"customer_id"`
	CompanyID  pgtype.UUID `json:"company_id"`
}

func (q *Queries) UpdateOverdueSalesAndAccountsGlobal(ctx context.Context) ([]UpdateOverdueSalesAndAccountsGlobalRow, error) {
	rows, err := q.db.Query(ctx, updateOverdueSalesAndAccountsGlobal)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []UpdateOverdueSalesAndAccountsGlobalRow{}
	for rows.Next() {
		var i UpdateOverdueSalesAndAccountsGlobalRow
		if err := rows.Scan(&i.SaleID, &i.CustomerID, &i.CompanyID); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const updateSale = `-- name: UpdateSale :exec
UPDATE sales
SET discount_amount = $1,
    subtotal = $2,
    total_amount = $3,
    installments_count = $4,
    down_payment = $5,
    due_days = $6,
    payment_method = $7,
    updated_at = CURRENT_TIMESTAMP,
    updated_by = $8,
    status = $9
WHERE id = $10
    AND company_id = $11
`

type UpdateSaleParams struct {
	DiscountAmount    pgtype.Numeric `json:"discount_amount"`
	Subtotal          pgtype.Numeric `json:"subtotal"`
	TotalAmount       pgtype.Numeric `json:"total_amount"`
	InstallmentsCount int32          `json:"installments_count"`
	DownPayment       pgtype.Numeric `json:"down_payment"`
	DueDays           pgtype.Int4    `json:"due_days"`
	PaymentMethod     interface{}    `json:"payment_method"`
	UpdatedBy         pgtype.UUID    `json:"updated_by"`
	Status            interface{}    `json:"status"`
	ID                pgtype.UUID    `json:"id"`
	CompanyID         pgtype.UUID    `json:"company_id"`
}

func (q *Queries) UpdateSale(ctx context.Context, arg UpdateSaleParams) error {
	_, err := q.db.Exec(ctx, updateSale,
		arg.DiscountAmount,
		arg.Subtotal,
		arg.TotalAmount,
		arg.InstallmentsCount,
		arg.DownPayment,
		arg.DueDays,
		arg.PaymentMethod,
		arg.UpdatedBy,
		arg.Status,
		arg.ID,
		arg.CompanyID,
	)
	return err
}

